    cr = round(x ** (1/3))

    # Check cr and nearby values for floating point safety
    for test_cr in [max(1, cr - 1), cr, cr + 1]:
        if test_cr ** 3 == x:
            # This is the actual cube root
            digit_sum = sum(int(d) for d in str(x))
            return digit_sum == test_cr

