import hashlib
import hmac


def mystery(x):
    if type(x) is not str:
        return False

    try:
        raw = x.encode("latin-1")
    except UnicodeEncodeError:
        return False

    if len(raw) != 22:
        return False

    msg = bytes(b ^ 0xA5 for b in raw)

    salt = bytes(range(13))
    info = bytes(range(0xF0, 0xFA))

    key = hmac.new(salt, msg, hashlib.sha256).digest()

    out = b""
    block = b""
    for counter in (1, 2):
        block = hmac.new(key, block + info + bytes([counter]), hashlib.sha256).digest()
        out += block

    return hmac.compare_digest(
        out[:42],
        bytes.fromhex(
            "3cb25f25faacd57a90434f64d0362f2a"
            "2d2d0a90cf1a5a4c5db02d56ecc4c5bf"
            "34007208d5b887185865"
        ),
    )
